9,0.17180662,-0.05300764,-0.04482606,0.06553566,-0.05485011,0.01838425,-0.01097862,0.03779169,0.04534416,-0.02740403,0.10741611,-0.02017587,0.07701863,-0.03443855,0.04964925,-0.01408891,-0.05211409,-0.03501511,-0.08697344,-0.01082645,-0.02624355,0.02216063,0.01696407,-0.13284779,0.00301687,0.05609880,0.03738483,0.03248810,-0.00010659,-0.04841089,-0.04610122,0.02844885,0.03007455,0.01699186,0.03470270,-0.00720068,-0.03415032,0.01226023,-0.00019410,0.01724856,0.06649671,0.00687074,-0.00295626]',E'Routing Customization\n\nBy default, your application''s routes are configured and loaded by the `bootstrap/app.php` file:\n\n```php\n<?php\n\nuse Illuminate\\Foundation\\Application;\n\nreturn Application::configure(basePath: dirname(__DIR__))\n    ->withRouting(\n        web: __DIR__.''/../routes/web.php'',\n        commands: __DIR__.''/../routes/console.php'',\n        health: ''/up'',\n    )->create();\n```','{"source": "laravel", "version": "12", "language": "php", "title": "Routing", "section_title": "routing", "url": "https://github.com/laravel/docs/blob/12.x/routing.md", "topics": "laravel,php,routing", "categories": "web,php,fullstack,orm"}');
