7340988,-0.04527895,0.01354817,0.03772385,-0.03805275,0.01276947,0.03363777,-0.02910271,0.01497465,-0.08174936,0.07616757,-0.02759278,0.06940515,-0.06109266,0.00400939,-0.01549274,-0.01860100,-0.06957670,-0.05629901,0.00280647,-0.10458535,0.06658803,0.06656067,-0.01375404,-0.03335288,0.02276885,-0.02690939,0.04321168,0.02405841,-0.05799763,-0.02858759,0.01723358,0.06526130,0.01428915,-0.03731778,-0.00589109,-0.07447629,0.03403363,-0.08248816,0.02127453,0.08761017,-0.07614332,0.00268128]',E'Inspecting the Current Route\n\nIf you would like to determine if the current request was routed to a given named route, you may use the `named` method on a Route instance. For example, you may check the current route name from a route middleware:\n\n```php\nuse Closure;\nuse Illuminate\\Http\\Request;\nuse Symfony\\Component\\HttpFoundation\\Response;\n\n/**\n * Handle an incoming request.\n *\n * @param  \\Closure(\\Illuminate\\Http\\Request): (\\Symfony\\Component\\HttpFoundation\\Response)  $next\n */\npublic function handle(Request $request, Closure $next): Response\n{\n    if ($request->route()->named(''profile'')) {\n        // ...\n    }\n\n    return $next($request);\n}\n```\n\n<a name="route-groups"></a>','{"source": "laravel", "version": "12", "language": "php", "title": "Routing", "section_title": "routing", "url": "https://github.com/laravel/docs/blob/12.x/routing.md", "topics": "laravel,php,routing", "categories": "web,php,fullstack,orm"}');
