10815,0.02557997,0.04340642,-0.03040114,0.06645603,-0.00317835,0.01731327,-0.01077976,-0.08142060,0.13922583,-0.02969999,0.05739736,-0.10117304,-0.00322844,-0.04593267,0.03427979,-0.02621640,-0.07797197,0.02083604,-0.07951146,-0.02289388,0.04322859,-0.01400308,-0.00157976,-0.02191958,-0.02111883,0.06323291,-0.00285092,-0.00123388,-0.07017758,-0.01664380,0.03439434,-0.00481117,-0.05471884,0.00845680,-0.03625987,0.00663231,-0.08016233,0.05467372,0.03396627,0.01918313,0.00086291]',E'Route Name Prefixes\n\nThe `name` method may be used to prefix each route name in the group with a given string. For example, you may want to prefix the names of all of the routes in the group with `admin`. The given string is prefixed to the route name exactly as it is specified, so we will be sure to provide the trailing `.` character in the prefix:\n\n```php\nRoute::name(''admin.'')->group(function () {\n    Route::get(''/users'', function () {\n        // Route assigned name "admin.users"...\n    })->name(''users'');\n});\n```\n\n<a name="route-model-binding"></a>','{"source": "laravel", "version": "12", "language": "php", "title": "Routing", "section_title": "routing", "url": "https://github.com/laravel/docs/blob/12.x/routing.md", "topics": "laravel,php,routing", "categories": "web,php,fullstack,orm"}');
