91,0.04582312,-0.00819494,-0.03426825,0.04042805,0.02078663,-0.09749485,0.01449864,0.04220791,0.02199569,-0.01149751,-0.02966467,0.00716140,-0.02965468,0.02615070,-0.07304390,-0.00817111,0.01367576,0.02522270,-0.00939876,-0.08998434,-0.01423299,0.05480790,0.02518026,-0.05266789,-0.00455128,0.00518335,-0.00401998,-0.04000222,-0.02099227,-0.00376659,0.00352451,0.04771034,-0.02436531,0.04160039,0.04322054,-0.01023847,0.00425603,-0.01907193,0.00762339,0.06822306,-0.05849110,-0.03643380,-0.01330933,-0.04392436,0.04823569,-0.00076036,0.02207433,-0.01620231,0.00069516,-0.02753917,-0.00632734,0.04280893,-0.02191074,0.00622041,-0.04407670,0.12131340,-0.28650957,-0.03401858,-0.03656615,0.00952585,-0.02537396,-0.07802159,0.02848434,0.01380864,-0.01066408,0.08401271,-0.00002582,-0.01283046,-0.05600139,0.02049631,0.00845009,0.08021978,0.00559359,-0.01443861,-0.03885010,-0.04584521,0.00584406,-0.01138425,-0.01396561,-0.05934366,0.02840868,0.04381056,0.09672335,0.00797690,-0.03363474,-0.06140690,0.04723809,-0.06837776,-0.02352548,0.01654874,-0.02706475,-0.01316207,0.00623555,-0.02513604,-0.00432648,0.00478762,-0.00260603,0.04834493,-0.00384958,0.01223992,0.01270785,-0.03292052,-0.02376391,0.03204715,-0.01580003,0.06610204,0.03569204,0.07526369,0.01876288,-0.01291172,0.04881828,0.02240052,-0.01144274,-0.03693103,-0.04258845,0.04060363,0.01423652,0.04081841,-0.03482166,0.01149411,0.03315012,0.00153482,0.01040736,-0.00612992,0.01508419,-0.02598727,-0.04041735,-0.03059623,-0.00009319,0.10439307,0.03378782,0.05677160,-0.00286887,-0.01118204,0.00099513,-0.00001753,0.04176266,-0.06542151,0.05334368,0.05407434,0.00979163,0.05635796,0.07137469,-0.01102095,-0.01251675,-0.01503632,-0.07344946,-0.00006019,-0.04049074,-0.01766699,-0.04359731,-0.05207456,-0.23445009,0.05991918,0.01454197,0.01300944,0.00796241,0.03320259,0.01165662,-0.04324766,0.03326756,0.01784914,0.08075562,0.05325618,0.00666586,-0.03071244,0.00121460,0.04732784,0.06790984,0.03697956,0.02898814,0.00572069,0.03001798,-0.00808144,0.19623384,0.00929031,0.02005272,0.02299924,0.00445006,-0.06249530,-0.04752024,0.02664027,-0.01187479,0.05728651,0.10239590,-0.00606961,-0.01724559,0.03714922,-0.03391992,0.04188548,-0.03477195,-0.05800157,-0.14118007,0.02053625,0.00284161,-0.01942530,0.09367425,-0.01184047,-0.03542045,-0.01910266,0.00644277,0.04577994,0.02138857,-0.03559225,0.01435893,0.00790294,0.05738102,0.02662210,-0.05918289,0.03591685,-0.00979618,0.08676065,-0.01145212,0.04970990,0.06813553,0.03448520,-0.00011741]',E'Subquery Selects\n\nEloquent also offers advanced subquery support, which allows you to pull information from related tables in a single query. For example, let''s imagine that we have a table of flight `destinations` and a table of `flights` to destinations. The `flights` table contains an `arrived_at` column which indicates when the flight arrived at the destination.\n\nUsing the subquery functionality available to the query builder''s `select` and `addSelect` methods, we can select all of the `destinations` and the name of the flight that most recently arrived at that destination using a single query:\n\n```php\nuse App\\Models\\Destination;\nuse App\\Models\\Flight;\n\nreturn Destination::addSelect([''last_flight'' => Flight::select(''name'')\n    ->whereColumn(''destination_id'', ''destinations.id'')\n    ->orderByDesc(''arrived_at'')\n    ->limit(1)\n])->get();\n```\n\n<a name="subquery-ordering"></a>','{"source": "laravel", "version": "12", "language": "php", "title": "Eloquent: Getting Started", "section_title": "eloquent", "url": "https://github.com/laravel/docs/blob/12.x/eloquent.md", "topics": "laravel,php,eloquent", "categories": "web,php,fullstack,orm"}');
