2513618,0.00614120,-0.03824351,0.04034244,0.01410483,-0.03572628,0.00366656,0.02935368,-0.03945559,0.01118277,-0.00528579,0.01017825,0.00104183,0.04817065,-0.01223141,-0.03010621,0.01802749,-0.00680963,0.01334499,-0.02293476,-0.04042628,0.00745797,0.04863020,0.01958324,-0.02429841,-0.00574933,0.04736527,-0.01283265,0.00050903,0.02456241,-0.00144133,-0.00171775,0.02821671,0.02428963,0.05544841,0.01412220,-0.00788898,-0.05429883,0.07026226,0.00463543,-0.05056800,-0.00168597,0.05178008,-0.07167870,-0.03086075,-0.06944352,-0.01889787,-0.01496200,0.03859379,0.02771706,0.06632209,-0.00804042,0.08195127,-0.04339733,-0.01775328,0.12716657,-0.31521636,-0.09174953,-0.01311965,0.07093897,0.01507819,-0.05065381,0.02423432,0.00419404,-0.08920824,0.10012849,-0.06866238,-0.00834669,-0.06074047,0.02789553,-0.02681768,0.05595538,0.04627578,-0.04310879,-0.06529924,-0.06315371,-0.05403953,-0.02787576,0.04246976,-0.11903274,0.05089923,-0.00518184,0.10372359,-0.02646456,-0.00300593,-0.00351017,0.03279726,-0.00828747,-0.04109038,-0.04784976,0.04596436,-0.02044527,-0.03972525,-0.05582214,0.00941632,-0.01873282,0.03856302,0.01969272,0.05635521,-0.01315877,-0.00402686,0.00171432,-0.01093454,-0.01554894,-0.03167789,0.05375397,0.01194012,0.05674852,0.01653347,0.05282809,-0.01663841,0.04463169,-0.07096580,-0.03422768,-0.05233730,0.04146554,0.03529371,0.01457420,0.00989166,-0.06060300,0.08525316,-0.02896097,-0.05719206,-0.06484039,0.06084700,0.03477246,0.03759236,0.02732246,-0.02127060,0.05607350,0.02534527,0.03175825,0.02979912,-0.04874934,0.03081213,0.05181776,0.04404958,-0.05847226,0.11754335,0.03852892,0.01586203,0.01636952,0.06489765,0.00543684,0.05760165,-0.02726138,-0.03241964,-0.03947032,-0.02075995,-0.01236176,-0.06049814,-0.03565662,-0.21963064,0.02303217,0.00416114,0.08818621,-0.06256078,0.00063652,0.01172093,-0.01897387,-0.00744975,-0.04097929,0.05850026,0.07393067,0.04358356,0.00428139,-0.08067236,0.08272354,0.03767847,-0.03870575,0.05181743,-0.01824657,0.00543624,-0.03516367,0.14376807,0.00122532,0.00918179,0.01587322,0.06615005,-0.03800290,-0.01207240,0.02685543,-0.02594670,0.00737786,0.10517685,-0.04183192,0.00125810,0.02574381,-0.00257235,0.03289887,0.04605396,-0.05903175,-0.07746720,0.00322100,-0.10084465,-0.00390996,0.07176568,-0.00587708,-0.03592053,0.03330552,-0.04903531,-0.01732287,-0.00125308,-0.01521319,0.00427303,0.06154817,0.04237127,0.05833646,-0.04197185,0.02559066,-0.01358729,0.00808666,0.00191490,0.02048463,0.02197787,0.02011286,-0.04338773]',E'Comparing Models\n\nSometimes you may need to determine if two models are the "same" or not. The `is` and `isNot` methods may be used to quickly verify two models have the same primary key, table, and database connection or not:\n\n```php\nif ($post->is($anotherPost)) {\n    // ...\n}\n\nif ($post->isNot($anotherPost)) {\n    // ...\n}\n```\n\nThe `is` and `isNot` methods are also available when using the `belongsTo`, `hasOne`, `morphTo`, and `morphOne` [relationships](/docs/{{version}}/eloquent-relationships). This method is particularly helpful when you would like to compare a related model without issuing a query to retrieve that model:\n\n```php\nif ($post->author()->is($user)) {\n    // ...\n}\n```\n\n<a name="events"></a>','{"source": "laravel", "version": "12", "language": "php", "title": "Eloquent: Getting Started", "section_title": "eloquent", "url": "https://github.com/laravel/docs/blob/12.x/eloquent.md", "topics": "laravel,php,eloquent", "categories": "web,php,fullstack,orm"}');
