,-0.05375955,-0.03729359,0.03510002,-0.01762541,0.03299546,0.04031051,-0.01541264,0.01158633,0.03329631,0.05404391,-0.01254409,0.00021306,-0.13214596,-0.04097446,0.03091452,-0.02867993,-0.02800345,-0.08306997,0.02095572,-0.03647454,0.00266973,0.05539666,0.00145932,-0.04418863,-0.06595851,-0.04121051,0.08942238,0.00107530,-0.07204395,-0.01744630,-0.05561737,0.05408398,-0.01749861,-0.02408078,-0.00154204,-0.01817596,0.07264072,0.01432863,0.01595583,0.06207605,-0.03489018,-0.06140595]',E'Middleware and Responses\n\nreturn $next($request);\n    }\n}\n```\n\nHowever, this middleware would perform its task **after** the request is handled by the application:\n\n```php\n<?php\n\nnamespace App\\Http\\Middleware;\n\nuse Closure;\nuse Illuminate\\Http\\Request;\nuse Symfony\\Component\\HttpFoundation\\Response;\n\nclass AfterMiddleware\n{\n    public function handle(Request $request, Closure $next): Response\n    {\n        $response = $next($request);\n\n        // Perform action\n\n        return $response;\n    }\n}\n```','{"source": "laravel", "version": "12", "language": "php", "title": "Middleware", "section_title": "middleware", "url": "https://github.com/laravel/docs/blob/12.x/middleware.md", "topics": "laravel,php,middleware", "categories": "web,php,fullstack,orm"}');
